#include <vector>
#include <string>
#include <algorithm>

std::vector<std::string> solve(std::vector<std::string> code, std::vector<std::string> businessLine, std::vector<bool> isActive) {
    std::vector<std::string> result;

    // Define the order of business lines
    std::vector<std::string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Iterate through each coupon
    for (size_t i = 0; i < code.size(); ++i) {
        // Check if the coupon is valid
        if (code[i].empty()) continue;
        if (businessLine[i] != "electronics" && businessLine[i] != "grocery" && 
            businessLine[i] != "pharmacy" && businessLine[i] != "restaurant") continue;
        if (!isActive[i]) continue;

        // Check if code contains only allowed characters
        bool isValidCode = true;
        for (char c : code[i]) {
            if (!std::isalnum(c) && c != '_') {
                isValidCode = false;
                break;
            }
        }
        if (!isValidCode) continue;

        // If all conditions are met, add to result
        result.push_back(code[i]);
    }

    // Sort the result first by business line order, then by code lexicographically
    std::sort(result.begin(), result.end(), [](const std::string& a, const std::string& b) {
        // Find the business line of each code
        std::string aBusiness = "";
        std::string bBusiness = "";
        for (size_t i = 0; i < code.size(); ++i) {
            if (code[i] == a) aBusiness = businessLine[i];
            if (code[i] == b) bBusiness = businessLine[i];
        }

        // Compare business lines based on the defined order
        for (size_t i = 0; i < businessOrder.size(); ++i) {
            if (aBusiness == businessOrder[i]) {
                for (size_t j = 0; j < businessOrder.size(); ++j) {
                    if (bBusiness == businessOrder[j]) {
                        return i < j;
                    }
                }
            }
        }
        return a < b;
    });

    return result;
}
