std::vector<std::string> solve(std::vector<std::string> code, std::vector<std::string> businessLine, std::vector<bool> isActive) {
    // Define the order of business lines
    std::vector<std::string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Filter valid coupons
    std::vector<std::string> validCodes;
    for (size_t i = 0; i < code.size(); ++i) {
        // Check if code is not empty and only contains allowed characters
        bool isValidCode = !code[i].empty() && code[i].find_first_not_of("abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_") == std::string::npos;

        // Check if business line is valid
        bool isValidBusiness = false;
        for (const auto& b : businessOrder) {
            if (b == businessLine[i]) {
                isValidBusiness = true;
                break;
            }
        }

        // Check if active
        bool isActiveBool = isActive[i];

        if (isValidCode && isValidBusiness && isActiveBool) {
            validCodes.push_back(code[i]);
        }
    }

    // Sort the valid codes first by business line order, then by code lexicographically
    std::sort(validCodes.begin(), validCodes.end(), [](const std::string& a, const std::string& b) {
        // Find the business line of each code
        std::string aBusinessLine = "";
        std::string bBusinessLine = "";
        for (size_t i = 0; i < code.size(); ++i) {
            if (code[i] == a) {
                aBusinessLine = businessLine[i];
            } else if (code[i] == b) {
                bBusinessLine = businessLine[i];
            }
        }

        // Compare business lines based on the defined order
        auto itA = std::find(businessOrder.begin(), businessOrder.end(), aBusinessLine);
        auto itB = std::find(businessOrder.begin(), businessOrder.end(), bBusinessLine);

        if (itA != itB) {
            return itA < itB;
        } else {
            return a < b;
        }
    });

    return validCodes;
}
